# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib.request
import urllib.error
import base64


def lambda_handler(event, context):
    """
    Lambda@Edge Viewer Request function that enriches requests by fetching
    additional data from URLs specified in request headers.
    
    Reads URLs from X-Enrich-URL headers (comma-separated if multiple),
    fetches data from each URL, and adds the enrichment data as new headers
    before forwarding to origin.
    """
    request = event['Records'][0]['cf']['request']
    headers = request.get('headers', {})
    
    # Check for the X-Enrich-URL header
    enrich_header_key = 'x-enrich-url'
    
    if enrich_header_key not in headers:
        # No enrichment requested, pass through
        return request
    
    # Extract all enrichment URLs from the header(s)
    enrich_urls = []
    for header_entry in headers[enrich_header_key]:
        # Support comma-separated URLs in a single header value
        urls = [url.strip() for url in header_entry['value'].split(',')]
        enrich_urls.extend(urls)
    
    # Validate and filter URLs - only allow HTTPS for security
    validated_urls = []
    for url in enrich_urls:
        if url and _is_valid_url(url):
            validated_urls.append(url)
    
    if not validated_urls:
        # Remove the enrichment header and pass through
        _remove_header(headers, enrich_header_key)
        return request
    
    # Fetch data from each enrichment URL
    enrichment_results = []
    for idx, url in enumerate(validated_urls):
        result = _fetch_url(url, timeout=2)
        enrichment_results.append({
            'url': url,
            'index': idx,
            'status': result.get('status'),
            'data': result.get('data'),
            'error': result.get('error')
        })
    
    # Add enrichment data as headers for the origin
    # Serialize the full enrichment payload as a base64-encoded JSON header
    enrichment_payload = json.dumps(enrichment_results)
    encoded_payload = base64.b64encode(enrichment_payload.encode('utf-8')).decode('utf-8')
    
    # Lambda@Edge has a header size limit (~8KB for viewer request)
    # Truncate if necessary
    max_header_size = 7680  # Leave some room under the 8KB limit
    if len(encoded_payload) <= max_header_size:
        headers['x-enrichment-data'] = [{
            'key': 'X-Enrichment-Data',
            'value': encoded_payload
        }]
    else:
        # If payload is too large, add truncated version with metadata
        headers['x-enrichment-data'] = [{
            'key': 'X-Enrichment-Data',
            'value': encoded_payload[:max_header_size]
        }]
        headers['x-enrichment-truncated'] = [{
            'key': 'X-Enrichment-Truncated',
            'value': 'true'
        }]
    
    # Add individual enrichment results as separate headers for easy access
    for result in enrichment_results:
        if result['status'] and result['data']:
            header_name = f'x-enrichment-{result["index"]}'
            # Truncate individual values if needed
            data_value = result['data'][:1024] if result['data'] else ''
            # Base64 encode to handle special characters
            encoded_value = base64.b64encode(data_value.encode('utf-8')).decode('utf-8')
            headers[header_name] = [{
                'key': f'X-Enrichment-{result["index"]}',
                'value': encoded_value
            }]
            # Add status header
            status_header_name = f'x-enrichment-{result["index"]}-status'
            headers[status_header_name] = [{
                'key': f'X-Enrichment-{result["index"]}-Status',
                'value': str(result['status'])
            }]
    
    # Add count of enrichment sources
    headers['x-enrichment-count'] = [{
        'key': 'X-Enrichment-Count',
        'value': str(len(enrichment_results))
    }]
    
    # Add enrichment success count
    success_count = sum(1 for r in enrichment_results if r['status'] and 200 <= r['status'] < 300)
    headers['x-enrichment-success-count'] = [{
        'key': 'X-Enrichment-Success-Count',
        'value': str(success_count)
    }]
    
    # Remove the original enrichment URL header to avoid leaking internal URLs to origin
    _remove_header(headers, enrich_header_key)
    
    request['headers'] = headers
    return request


def _is_valid_url(url):
    """
    Validate that the URL is safe to fetch.
    Only allows HTTPS URLs to prevent data exfiltration and SSRF attacks.
    Blocks private/internal IP ranges and localhost.
    """
    if not url:
        return False
    
    # Only allow https
    if not url.startswith('https://'):
        return False
    
    # Block common internal/private hostnames
    blocked_patterns = [
        'https://localhost',
        'https://127.',
        'https://10.',
        'https://172.16.',
        'https://172.17.',
        'https://172.18.',
        'https://172.19.',
        'https://172.20.',
        'https://172.21.',
        'https://172.22.',
        'https://172.23.',
        'https://172.24.',
        'https://172.25.',
        'https://172.26.',
        'https://172.27.',
        'https://172.28.',
        'https://172.29.',
        'https://172.30.',
        'https://172.31.',
        'https://192.168.',
        'https://169.254.',
        'https://[',
        'https://0.',
    ]
    
    url_lower = url.lower()
    for pattern in blocked_patterns:
        if url_lower.startswith(pattern):
            return False
    
    # Block metadata endpoints
    if '169.254.169.254' in url_lower:
        return False
    
    return True


def _fetch_url(url, timeout=2):
    """
    Fetch data from a URL with timeout and error handling.
    
    Uses urllib.request since Lambda@Edge has limited package availability
    (requests library is not available by default, but urllib is).
    
    Args:
        url: The URL to fetch
        timeout: Request timeout in seconds (keep low for edge performance)
    
    Returns:
        dict with 'status', 'data', and 'error' keys
    """
    result = {
        'status': None,
        'data': None,
        'error': None
    }
    
    try:
        req = urllib.request.Request(
            url,
            method='GET',
            headers={
                'User-Agent': 'LambdaEdge-Enrichment/1.0',
                'Accept': 'application/json, text/plain, */*',
                'Connection': 'close'
            }
        )
        
        with urllib.request.urlopen(req, timeout=timeout) as response:
            result['status'] = response.getcode()
            # Read up to 4KB of response data to prevent memory issues at edge
            raw_data = response.read(4096)
            
            # Determine encoding
            content_type = response.headers.get('Content-Type', '')
            encoding = 'utf-8'
            if 'charset=' in content_type:
                encoding = content_type.split('charset=')[-1].split(';')[0].strip()
            
            result['data'] = raw_data.decode(encoding, errors='replace')
            
    except urllib.error.HTTPError as e:
        result['status'] = e.code
        result['error'] = f'HTTP {e.code}: {e.reason}'
        # Try to read error response body
        try:
            error_body = e.read(1024)
            result['data'] = error_body.decode('utf-8', errors='replace')
        except Exception:
            pass
            
    except urllib.error.URLError as e:
        result['error'] = f'URL Error: {str(e.reason)}'
        
    except TimeoutError:
        result['error'] = f'Timeout after {timeout}s'
        
    except Exception as e:
        result['error'] = f'Unexpected error: {str(e)}'
    
    return result


def _remove_header(headers, header_name):
    """
    Remove a header from the CloudFront headers dict (case-insensitive).
    """
    lower_name = header_name.lower()
    keys_to_remove = [k for k in headers if k.lower() == lower_name]
    for key in keys_to_remove:
        del headers[key]